    function source(end: any, cb: Function) {
      if (end) return cb(end)
      let i = 0
      const values = [1, 2, 3]
      return function next(end: any, cb: Function) {
        if (end) return cb(end)
        if (i >= values.length) return cb(true)
        cb(null, values[i++])
      }
    }

